	&lt;li&gt;&lt;span class=&quot;VIiyi&quot; lang=&quot;hi&quot;&gt;&lt;span class=&quot;JLqJ4b ChMk0b&quot; data-language-for-alternatives=&quot;hi&quot; data-language-to-translate-into=&quot;en&quot; data-number-of-phrases=&quot;1&quot; data-phrase-index=&quot;0&quot;&gt;&lt;span&gt;यह सारणी एक्सेल में सबसे अधिक उपयोग किए जाने वाले शॉर्टकट को सूचीबद्ध करती है।&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/li&gt;
